-- ======================================================================
-- STEP 7/13: 06_HTN_Reports
-- ======================================================================

-- ============================================================================
-- HYPERTENSION (HTN) — REPORT VIEWS
-- ============================================================================
-- Creates 3 report views from the analytical grain:
--   1. rpt_htn_screening_monthly  — Monthly screening rates by BP category
--   2. rpt_htn_prevalence_annual  — Annual I10 prevalence snapshot
--   3. rpt_htn_incidence_monthly  — Monthly new I10 case rate
--
-- All reports include per-health_cluster breakdowns, cluster subtotals, and a
-- grand total row ("── ALL CLUSTERS ──").
--
-- Prerequisites: 00_config.sql, htn_staging_views.sql, htn_analytical_view.sql
-- ============================================================================


-- ############################################################################
-- REPORT 1: SCREENING (MONTHLY)
-- ############################################################################
-- Denominator: at-risk patients at month start (no HTN diagnosis before month)
-- Numerator:   at-risk patients who had BOTH SYS and DIA this month
-- Stratified:  normal / elevated / abnormal (Stage 1+2 HTN combined)
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_htn_screening_monthly AS

WITH screening_metrics AS (
    SELECT
        health_cluster,
        report_year,
        report_month,
        year_month_key,
        COUNT(DISTINCT CASE WHEN is_at_risk_start = TRUE
                        THEN patient_key END)   AS at_risk_population,
        COUNT(DISTINCT CASE WHEN is_screened = TRUE
                        THEN patient_key END)   AS screened_count,
        COUNT(DISTINCT CASE WHEN is_screened = TRUE
                              AND screening_category = 'normal'
                        THEN patient_key END)   AS normal_count,
        COUNT(DISTINCT CASE WHEN is_screened = TRUE
                              AND screening_category = 'elevated'
                        THEN patient_key END)   AS elevated_count,
        COUNT(DISTINCT CASE WHEN is_screened = TRUE
                              AND screening_category = 'abnormal'
                        THEN patient_key END)   AS abnormal_count,
        ROUND(screened_count / NULLIF(at_risk_population, 0) * 100, 4)
                                                AS screening_rate_pct,
        ROUND(abnormal_count / NULLIF(screened_count, 0) * 100, 4)
                                                AS abnormal_rate_pct
    FROM CHI_REPORTING.stg_htn_patient_month
    GROUP BY health_cluster, report_year, report_month, year_month_key
)

-- Monthly detail rows (sort_order=0)
SELECT
    report_year                              AS year,
    health_cluster,
    TO_VARCHAR(
        TO_DATE(year_month_key::VARCHAR || '01', 'YYYYMMDD'),
        'MON YYYY'
    )                                        AS period,
    at_risk_population,
    screened_count,
    normal_count,
    elevated_count,
    abnormal_count,
    screening_rate_pct,
    abnormal_rate_pct,
    year_month_key                           AS sort_key,
    0                                        AS sort_order
FROM screening_metrics

UNION ALL

-- Cluster subtotal rows (sort_order=1)
SELECT
    report_year                              AS year,
    health_cluster,
    '── ' || health_cluster || ' TOTAL ──'  AS period,
    SUM(at_risk_population)                  AS at_risk_population,
    SUM(screened_count)                      AS screened_count,
    SUM(normal_count)                        AS normal_count,
    SUM(elevated_count)                      AS elevated_count,
    SUM(abnormal_count)                      AS abnormal_count,
    ROUND(SUM(screened_count) / NULLIF(SUM(at_risk_population), 0) * 100, 4)
                                              AS screening_rate_pct,
    ROUND(SUM(abnormal_count) / NULLIF(SUM(screened_count), 0) * 100, 4)
                                              AS abnormal_rate_pct,
    99999                                    AS sort_key,
    1                                        AS sort_order
FROM screening_metrics
GROUP BY health_cluster, report_year

UNION ALL

-- Grand total row — all clusters combined (sort_order=2)
SELECT
    report_year                              AS year,
    '── ALL CLUSTERS ──'                    AS health_cluster,
    '── ' || report_year || ' ALL CLUSTERS ──' AS period,
    SUM(at_risk_population)                  AS at_risk_population,
    SUM(screened_count)                      AS screened_count,
    SUM(normal_count)                        AS normal_count,
    SUM(elevated_count)                      AS elevated_count,
    SUM(abnormal_count)                      AS abnormal_count,
    ROUND(SUM(screened_count) / NULLIF(SUM(at_risk_population), 0) * 100, 4)
                                              AS screening_rate_pct,
    ROUND(SUM(abnormal_count) / NULLIF(SUM(screened_count), 0) * 100, 4)
                                              AS abnormal_rate_pct,
    99999                                    AS sort_key,
    2                                        AS sort_order
FROM screening_metrics
GROUP BY report_year

ORDER BY health_cluster, sort_order, sort_key;


-- ############################################################################
-- REPORT 2: PREVALENCE (ANNUAL)
-- ############################################################################
-- Denominator: total eligible population at Jan 1 (age>18, National ID, alive)
-- Numerator:   all patients with ICD-10 I10 at Dec 31 of the report year
-- Sub-counts:  incident during year, pre-existing before year
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_htn_prevalence_annual AS

WITH prevalence_snapshot AS (
    SELECT
        patient_key,
        first_i10_date,
        CASE WHEN first_i10_date IS NOT NULL
              AND first_i10_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                                     AS has_i10_at_year_end,
        CASE WHEN first_i10_date >= cfg.report_start
              AND first_i10_date < cfg.report_end
             THEN TRUE ELSE FALSE
        END                                     AS is_incident_this_year,
        CASE WHEN first_i10_date < cfg.report_start
             THEN TRUE ELSE FALSE
        END                                     AS is_pre_existing
    FROM CHI_REPORTING.stg_htn_cohort
    CROSS JOIN CHI_REPORTING.chi_config cfg
)

-- Per-cluster rows (sort_order=0)
SELECT
    cfg.report_year                             AS year,
    bc.health_cluster,
    COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE
                    THEN bc.patient_key END)    AS total_population,
    COUNT(DISTINCT CASE WHEN ps.has_i10_at_year_end = TRUE
                    THEN bc.patient_key END)    AS prevalent_htn_count,
    COUNT(DISTINCT CASE WHEN ps.is_incident_this_year = TRUE
                    THEN bc.patient_key END)    AS incident_during_year,
    COUNT(DISTINCT CASE WHEN ps.is_pre_existing = TRUE
                          AND ps.has_i10_at_year_end = TRUE
                    THEN bc.patient_key END)    AS pre_existing_htn_count,
    ROUND(prevalent_htn_count / NULLIF(total_population, 0) * 100, 4)
                                                AS prevalence_rate_pct,
    bc.health_cluster                           AS period_label,
    0                                           AS sort_order
FROM CHI_REPORTING.stg_htn_cohort bc
CROSS JOIN CHI_REPORTING.chi_config cfg
LEFT JOIN prevalence_snapshot ps USING (patient_key)
GROUP BY cfg.report_year, bc.health_cluster

UNION ALL

-- Grand total row — all clusters combined (sort_order=2)
SELECT
    cfg.report_year                             AS year,
    '── ALL CLUSTERS ──'                       AS health_cluster,
    COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE
                    THEN bc.patient_key END)    AS total_population,
    COUNT(DISTINCT CASE WHEN ps.has_i10_at_year_end = TRUE
                    THEN bc.patient_key END)    AS prevalent_htn_count,
    COUNT(DISTINCT CASE WHEN ps.is_incident_this_year = TRUE
                    THEN bc.patient_key END)    AS incident_during_year,
    COUNT(DISTINCT CASE WHEN ps.is_pre_existing = TRUE
                          AND ps.has_i10_at_year_end = TRUE
                    THEN bc.patient_key END)    AS pre_existing_htn_count,
    ROUND(COUNT(DISTINCT CASE WHEN ps.has_i10_at_year_end = TRUE THEN bc.patient_key END)
          / NULLIF(COUNT(DISTINCT CASE WHEN bc.is_in_total_population = TRUE THEN bc.patient_key END), 0) * 100, 4)
                                                AS prevalence_rate_pct,
    '── ' || cfg.report_year || ' ALL CLUSTERS ──' AS period_label,
    2                                           AS sort_order
FROM CHI_REPORTING.stg_htn_cohort bc
CROSS JOIN CHI_REPORTING.chi_config cfg
LEFT JOIN prevalence_snapshot ps USING (patient_key)

ORDER BY health_cluster, sort_order;


-- ############################################################################
-- REPORT 3: INCIDENCE (MONTHLY)
-- ############################################################################
-- Denominator: at-risk population at month START (no HTN diagnosis before month)
-- Numerator:   patients who received first-ever I10 this month
-- Rate:        per 100,000 at-risk population
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.rpt_htn_incidence_monthly AS

WITH incidence_metrics AS (
    SELECT
        health_cluster,
        report_year,
        report_month,
        year_month_key,
        COUNT(DISTINCT CASE WHEN is_at_risk_start = TRUE
                        THEN patient_key END)   AS at_risk_population_start,
        COUNT(DISTINCT CASE WHEN is_incident_case = TRUE
                        THEN patient_key END)   AS incident_cases,
        ROUND(incident_cases / NULLIF(at_risk_population_start, 0) * 100000, 2)
                                                AS incidence_rate_per_100k
    FROM CHI_REPORTING.stg_htn_patient_month
    GROUP BY health_cluster, report_year, report_month, year_month_key
)

-- Monthly detail rows (sort_order=0)
SELECT
    report_year                              AS year,
    health_cluster,
    TO_VARCHAR(
        TO_DATE(year_month_key::VARCHAR || '01', 'YYYYMMDD'),
        'MON YYYY'
    )                                        AS period,
    at_risk_population_start,
    incident_cases,
    incidence_rate_per_100k,
    year_month_key                           AS sort_key,
    0                                        AS sort_order
FROM incidence_metrics

UNION ALL

-- Cluster subtotal rows (sort_order=1)
-- Annual rate = total cases / January at-risk × 100,000
SELECT
    report_year                              AS year,
    health_cluster,
    '── ' || health_cluster || ' TOTAL ──'  AS period,
    NULL                                     AS at_risk_population_start,
    SUM(incident_cases)                      AS incident_cases,
    ROUND(SUM(incident_cases) / NULLIF(
        MAX(CASE WHEN report_month = 1 THEN at_risk_population_start END), 0
    ) * 100000, 2)                           AS incidence_rate_per_100k,
    99999                                    AS sort_key,
    1                                        AS sort_order
FROM incidence_metrics
GROUP BY health_cluster, report_year

UNION ALL

-- Grand total row — all clusters combined (sort_order=2)
-- Annual rate = total cases / total January at-risk × 100,000
SELECT
    report_year                              AS year,
    '── ALL CLUSTERS ──'                    AS health_cluster,
    '── ' || report_year || ' ALL CLUSTERS ──' AS period,
    NULL                                     AS at_risk_population_start,
    SUM(incident_cases)                      AS incident_cases,
    ROUND(SUM(incident_cases) / NULLIF(
        SUM(CASE WHEN report_month = 1 THEN at_risk_population_start END), 0
    ) * 100000, 2)                           AS incidence_rate_per_100k,
    99999                                    AS sort_key,
    2                                        AS sort_order
FROM incidence_metrics
GROUP BY report_year

ORDER BY health_cluster, sort_order, sort_key;


-- ============================================================================
-- FINAL OUTPUT
-- ============================================================================
-- (1) Screening Report — Monthly
-- SELECT * FROM CHI_REPORTING.rpt_htn_screening_monthly ORDER BY health_cluster, sort_order, sort_key;

-- (2) Prevalence Report — Annual
-- SELECT * FROM CHI_REPORTING.rpt_htn_prevalence_annual ORDER BY health_cluster, sort_order;

-- (3) Incidence Report — Monthly
-- SELECT * FROM CHI_REPORTING.rpt_htn_incidence_monthly ORDER BY health_cluster, sort_order, sort_key;
-- ============================================================================



-- ======================================================================
-- STEP 8/13: 07_DLP_Staging
-- ======================================================================

-- ============================================================================
-- DYSLIPIDEMIA (DLP) — STAGING VIEWS
-- ============================================================================
-- Creates 3 staging views that extract and prepare source data:
--   1. stg_dlp_cohort       — patient × year grain (demographics + diagnosis flags)
--   2. stg_dlp_diagnosis    — patient × diagnosis grain (ICD-10 E78 records)
--   3. stg_dlp_labs         — patient × visit grain (HDL/LDL/CHOL/TRIG, LABS+OBS)
--
-- Prerequisites: Run 00_config.sql first (creates CHI_REPORTING.chi_config)
--
-- Data sources (LABRESULTS + OBSERVATIONS — same pattern as DM):
--   NMR.LEANHIS.PATIENTS
--   NMR.LEANHIS.PATIENTVISITS
--   NMR.LEANHIS.LABRESULTS / LABRESULTS_RESULTVALUES
--   NMR.LEANHIS.OBSERVATIONS / OBSERVATIONS_OBSERVATIONVALUES
--   NMR.LEANHIS.DIAGNOSIS_CODES  [PLACEHOLDER]
-- ============================================================================


-- ############################################################################
-- VIEW 1: stg_dlp_cohort
-- ############################################################################
-- Grain: one row per patient per report year.
-- Identifies every eligible patient and joins DLP diagnosis history to assign
-- cohort membership: is_in_total_population, is_in_at_risk, is_dlp_prevalent.
-- Also provides the first-ever E78 diagnosis date (for incidence detection).
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.stg_dlp_cohort AS

WITH total_population AS (
    SELECT
        p._ID                                   AS patient_key,
        p.GENDERUID                             AS gender,
        p.DATEOFBIRTH                           AS date_of_birth,
        DATEDIFF(YEAR, p.DATEOFBIRTH, cfg.report_start) AS age_at_jan1,
        CASE WHEN age_at_jan1 > 18
              AND p.NATIONALID IS NOT NULL
              AND p.NATIONALID <> ''
              AND (p.DATEOFDEATH IS NULL OR p.DATEOFDEATH >= cfg.report_start)
             THEN TRUE ELSE FALSE
        END                                     AS is_in_total_population
    FROM NMR.LEANHIS.PATIENTS p
    CROSS JOIN CHI_REPORTING.chi_config cfg
    WHERE p.DATEOFBIRTH <= DATEADD(YEAR, -18, cfg.report_start)
),

dlp_diagnosis_summary AS (
    SELECT
        PATIENTUID                              AS patient_key,
        MIN(DIAGNOSIS_DATE)                     AS first_e78_date,
        MIN(DIAGNOSIS_DATE)                     AS first_any_dlp_date,
        TRUE                                    AS has_e78
    FROM NMR.LEANHIS.DIAGNOSIS_CODES                                -- [PLACEHOLDER]
    WHERE TRIM(UPPER(ICD10_CODE)) = 'E78'                           -- [PLACEHOLDER]
    GROUP BY PATIENTUID
),

phc_assignment AS (
    SELECT PATIENTUID AS patient_key, HEALTH_CLUSTER AS health_cluster_raw
    FROM NMR.LEANHIS.PHC_ASSIGNMENT
)

SELECT
    tp.patient_key,
    tp.gender,
    tp.age_at_jan1,
    tp.is_in_total_population,
    COALESCE(phc.health_cluster_raw, 'Unassigned') AS health_cluster,
    dx.first_any_dlp_date,
    dx.first_e78_date,
    COALESCE(dx.has_e78, FALSE)                 AS has_e78,
    COALESCE(dx.has_e78, FALSE)                 AS has_any_dlp_diagnosis,
    CASE WHEN tp.is_in_total_population
          AND NOT COALESCE(dx.has_e78, FALSE)
         THEN TRUE ELSE FALSE
    END                                         AS is_in_at_risk,
    CASE WHEN tp.is_in_total_population
          AND COALESCE(dx.has_e78, FALSE)
         THEN TRUE ELSE FALSE
    END                                         AS is_dlp_prevalent
FROM total_population tp
LEFT JOIN phc_assignment phc USING (patient_key)
LEFT JOIN dlp_diagnosis_summary dx USING (patient_key);


-- ############################################################################
-- VIEW 2: stg_dlp_diagnosis
-- ############################################################################
-- Grain: one row per diagnosis record.
-- Extracts all E78 (Dyslipidemia) ICD-10 codes with first-occurrence rank.
-- Useful for debugging: see exactly when each patient was diagnosed.
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.stg_dlp_diagnosis AS

SELECT
    patient_key,
    diagnosis_date,
    icd10_code,
    icd10_description,
    ROW_NUMBER() OVER (
        PARTITION BY patient_key, icd10_code
        ORDER BY diagnosis_date
    )                                           AS diagnosis_rank
FROM (
    SELECT
        PATIENTUID                              AS patient_key,        -- [PLACEHOLDER]
        TO_DATE(DIAGNOSIS_DATE)                 AS diagnosis_date,     -- [PLACEHOLDER]
        TRIM(UPPER(ICD10_CODE))                 AS icd10_code,         -- [PLACEHOLDER]
        DIAGNOSIS_DESCRIPTION                   AS icd10_description   -- [PLACEHOLDER]
    FROM NMR.LEANHIS.DIAGNOSIS_CODES                                   -- [PLACEHOLDER]
    WHERE TRIM(UPPER(ICD10_CODE)) = 'E78'                              -- [PLACEHOLDER]
) raw;


-- ############################################################################
-- VIEW 3: stg_dlp_labs
-- ############################################################################
-- Grain: one row per lipid result per patient per visit.
-- Extracts 4 lipid markers from both LABRESULTS and OBSERVATIONS (UNION ALL).
-- Standardizes result names: HDL, LDL, CHOL, TRIG.
-- NOTE: Gender-specific HDL classification happens downstream in stg_dlp_patient_month.
-- ############################################################################

CREATE OR REPLACE VIEW CHI_REPORTING.stg_dlp_labs AS

-- Step 1 — Lipid panel from LABRESULTS
SELECT
    lr.PATIENTUID                               AS patient_key,
    TO_DATE(pv.STARTDATE)                       AS visit_date,
    YEAR(pv.STARTDATE) * 100 + MONTH(pv.STARTDATE) AS year_month_key,
    CASE
        WHEN lrv.NAME IN (
            'Cholesterol.in HDL',
            'Cholesterol in HDL'
        ) THEN 'HDL'
        WHEN lrv.NAME IN (
            'Cholesterol.in LDL',
            'Cholesterol in LDL [Mass/volume] in Serum or Plasma by Direct assay'
        ) THEN 'LDL'
        WHEN lrv.NAME = 'Cholesterol in Serum or Plasma' THEN 'CHOL'
        WHEN lrv.NAME = 'Triglyceride' THEN 'TRIG'
    END                                         AS result_name,
    NULLIF(
        TRY_TO_DECIMAL(
            REGEXP_SUBSTR(lrv.RESULTVALUE, '[0-9]+(\\.[0-9]+)?'),
            10, 2
        ), 0
    )                                           AS result_value,
    'LABRESULTS'                                AS source_table
FROM NMR.LEANHIS.LABRESULTS lr
JOIN NMR.LEANHIS.LABRESULTS_RESULTVALUES lrv
    ON lr._ID = lrv.LABRESULTS_ID
JOIN NMR.LEANHIS.PATIENTVISITS pv
    ON lr.PATIENTVISITUID = pv._ID
CROSS JOIN CHI_REPORTING.chi_config cfg
WHERE pv.STARTDATE >= cfg.report_start
  AND pv.STARTDATE <  cfg.report_end
  AND lrv.NAME IN (
          'Cholesterol.in HDL',
          'Cholesterol in HDL',
          'Cholesterol.in LDL',
          'Cholesterol in LDL [Mass/volume] in Serum or Plasma by Direct assay',
          'Cholesterol in Serum or Plasma',
          'Triglyceride'
      )

UNION ALL

-- Step 2 — HDL and Triglyceride from OBSERVATIONS
SELECT
    o.PATIENTUID                                AS patient_key,
    TO_DATE(pv.STARTDATE)                       AS visit_date,
    YEAR(pv.STARTDATE) * 100 + MONTH(pv.STARTDATE) AS year_month_key,
    CASE
        WHEN ov.NAME IN (
            'Cholesterol.in HDL',
            'Cholesterol in HDL'
        ) THEN 'HDL'
        WHEN ov.NAME = 'Triglyceride' THEN 'TRIG'
    END                                         AS result_name,
    NULLIF(
        TRY_TO_DECIMAL(
            REGEXP_SUBSTR(ov.RESULTVALUE, '[0-9]+(\\.[0-9]+)?'),
            10, 2
        ), 0
    )                                           AS result_value,
    'OBSERVATIONS'                              AS source_table
FROM NMR.LEANHIS.OBSERVATIONS o
JOIN NMR.LEANHIS.OBSERVATIONS_OBSERVATIONVALUES ov
    ON o._ID = ov.OBSERVATIONS_ID
JOIN NMR.LEANHIS.PATIENTVISITS pv
    ON o.PATIENTVISITUID = pv._ID
CROSS JOIN CHI_REPORTING.chi_config cfg
WHERE pv.STARTDATE >= cfg.report_start
  AND pv.STARTDATE <  cfg.report_end
  AND ov.NAME IN (
          'Cholesterol.in HDL',
          'Cholesterol in HDL',
          'Triglyceride'
      );


-- ============================================================================
-- VERIFY
-- ============================================================================
-- SELECT COUNT(*) AS cohort_rows FROM CHI_REPORTING.stg_dlp_cohort;
-- SELECT COUNT(*) AS diagnosis_rows FROM CHI_REPORTING.stg_dlp_diagnosis;
-- SELECT result_name, COUNT(*) FROM CHI_REPORTING.stg_dlp_labs GROUP BY 1;
